import json
s=json.load(open('figure_review/slots.json'))
tg=[]
for g in s['groups']:
    if 'target' in g: tg.append(g['target'])
    if 'target_pattern' in g:
        for it in g.get('items',[]): tg.append(g['target_pattern'].format(**it))
print('\n'.join(tg)); print('N targets:', len(tg))
"
